import React, { useCallback, useEffect, useMemo, useState } from "react";
import axios from "axios";
import { io } from "socket.io-client";
import API_BASE_URL from "../../config/api";

const ROLE_OPTIONS = ["owner", "admin", "member", "viewer"];
const PAGE_SIZE = 10;

const socket = io(API_BASE_URL, { autoConnect: true });

const initialsFromName = (name = "") =>
  name
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((token) => token[0]?.toUpperCase())
    .join("") || "NA";

const TeamMembers = ({ workspaceId }) => {
  const currentUserId = sessionStorage.getItem("user_id");

  const [members, setMembers] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedRole, setSelectedRole] = useState("");
  const [page, setPage] = useState(1);
  const [summary, setSummary] = useState({ joined: 0, capacity: 10 });
  const [pagination, setPagination] = useState({ page: 1, totalPages: 1, total: 0 });
  const [permissions, setPermissions] = useState({ can_manage: false, requester_role: null });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [inviteOpen, setInviteOpen] = useState(false);
  const [inviteForm, setInviteForm] = useState({ email: "", role: "member" });
  const [inviteLoading, setInviteLoading] = useState(false);

  const capacityPercent = useMemo(() => {
    if (!summary.capacity) return 0;
    return Math.min(Math.round((summary.joined / summary.capacity) * 100), 100);
  }, [summary]);

  const fetchMembers = useCallback(async () => {
    if (!workspaceId || !currentUserId) return;
    setLoading(true);
    setError("");
    try {
      const response = await axios.get(`${API_BASE_URL}/api/workspace/${workspaceId}/members`, {
        params: {
          requester_id: currentUserId,
          search,
          role: selectedRole,
          page,
          limit: PAGE_SIZE,
        },
      });
      setMembers(response.data.data || []);
      setSummary(response.data.summary || { joined: 0, capacity: 10 });
      setPagination(response.data.pagination || { page: 1, totalPages: 1, total: 0 });
      setPermissions(response.data.permissions || { can_manage: false, requester_role: null });
    } catch (err) {
      setError(err.response?.data?.message || "Failed to load workspace members");
    } finally {
      setLoading(false);
    }
  }, [workspaceId, currentUserId, search, selectedRole, page]);

  useEffect(() => {
    fetchMembers();
  }, [fetchMembers]);

  useEffect(() => {
    if (!workspaceId || !currentUserId) return undefined;

    socket.emit("join_workspace", String(workspaceId));

    const pingPresence = () =>
      socket.emit("workspace_presence_ping", {
        workspace_id: workspaceId,
        user_id: Number(currentUserId),
      });

    pingPresence();
    const presenceTimer = setInterval(pingPresence, 60 * 1000);

    const handleRefresh = () => fetchMembers();
    socket.on("workspace_members_updated", handleRefresh);
    socket.on("workspace_presence_updated", handleRefresh);

    return () => {
      clearInterval(presenceTimer);
      socket.off("workspace_members_updated", handleRefresh);
      socket.off("workspace_presence_updated", handleRefresh);
    };
  }, [workspaceId, currentUserId, fetchMembers]);

  const handleInvite = async (event) => {
    event.preventDefault();
    if (!inviteForm.email.trim()) return;

    setInviteLoading(true);
    setError("");
    try {
      await axios.post(`${API_BASE_URL}/api/workspace/${workspaceId}/invite`, {
        email: inviteForm.email.trim(),
        role: inviteForm.role,
        inviter_id: Number(currentUserId),
      });
      setInviteForm({ email: "", role: "member" });
      setInviteOpen(false);
      setPage(1);
      await fetchMembers();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to invite member");
    } finally {
      setInviteLoading(false);
    }
  };

  const handleRoleChange = async (memberId, nextRole) => {
    try {
      await axios.put(`${API_BASE_URL}/api/workspace/member/${memberId}/role`, {
        role: nextRole,
        requester_id: Number(currentUserId),
      });
      fetchMembers();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update role");
    }
  };

  const handleRemove = async (memberId) => {
    if (!window.confirm("Remove this member from workspace?")) return;
    try {
      await axios.delete(`${API_BASE_URL}/api/workspace/member/${memberId}`, {
        data: { requester_id: Number(currentUserId) },
      });
      fetchMembers();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to remove member");
    }
  };

  return (
    <section className="w-full rounded-2xl bg-white p-4 shadow-sm md:p-6">
      <div className="mb-4 flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Workspace Members</h2>
          <p className="mt-1 text-sm text-slate-600">
            {summary.joined} / {summary.capacity} Members Joined
          </p>
          <div className="mt-2 h-2 w-64 rounded-full bg-slate-200">
            <div
              className="h-2 rounded-full bg-emerald-500 transition-all"
              style={{ width: `${capacityPercent}%` }}
            />
          </div>
        </div>
        {permissions.can_manage && (
          <button
            type="button"
            onClick={() => setInviteOpen((value) => !value)}
            className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-700"
          >
            Invite Member
          </button>
        )}
      </div>

      {inviteOpen && permissions.can_manage && (
        <form onSubmit={handleInvite} className="mb-4 grid gap-3 rounded-xl border border-slate-200 p-4 md:grid-cols-3">
          <input
            type="email"
            value={inviteForm.email}
            onChange={(event) => setInviteForm((prev) => ({ ...prev, email: event.target.value }))}
            placeholder="Enter member email"
            className="rounded-lg border border-slate-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none"
            required
          />
          <select
            value={inviteForm.role}
            onChange={(event) => setInviteForm((prev) => ({ ...prev, role: event.target.value }))}
            className="rounded-lg border border-slate-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none"
          >
            {ROLE_OPTIONS.map((roleOption) => (
              <option value={roleOption} key={roleOption}>
                {roleOption}
              </option>
            ))}
          </select>
          <button
            type="submit"
            disabled={inviteLoading}
            className="rounded-lg bg-emerald-600 px-3 py-2 text-sm font-semibold text-white transition hover:bg-emerald-700 disabled:cursor-not-allowed disabled:bg-emerald-400"
          >
            {inviteLoading ? "Inviting..." : "Send Invite"}
          </button>
        </form>
      )}

      <div className="mb-4 grid gap-3 md:grid-cols-2">
        <input
          value={search}
          onChange={(event) => {
            setPage(1);
            setSearch(event.target.value);
          }}
          placeholder="Search by name or email"
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none"
        />
        <select
          value={selectedRole}
          onChange={(event) => {
            setPage(1);
            setSelectedRole(event.target.value);
          }}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none"
        >
          <option value="">All Roles</option>
          {ROLE_OPTIONS.map((roleOption) => (
            <option value={roleOption} key={roleOption}>
              {roleOption}
            </option>
          ))}
        </select>
      </div>

      {error && <p className="mb-3 rounded-lg bg-red-50 px-3 py-2 text-sm text-red-700">{error}</p>}

      <div className="overflow-x-auto rounded-xl border border-slate-200">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50 text-left text-xs uppercase text-slate-500">
            <tr>
              <th className="px-4 py-3">Avatar</th>
              <th className="px-4 py-3">Name</th>
              <th className="px-4 py-3">Email</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">Role</th>
              <th className="px-4 py-3">Joined Date</th>
              <th className="px-4 py-3">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 bg-white text-sm text-slate-700">
            {!loading && members.length === 0 && (
              <tr>
                <td colSpan="7" className="px-4 py-8 text-center text-slate-500">
                  No members found
                </td>
              </tr>
            )}
            {members.map((member) => (
              <tr key={member.id} className="transition hover:bg-slate-50">
                <td className="px-4 py-3">
                  <div className="flex h-9 w-9 items-center justify-center rounded-full bg-indigo-100 text-xs font-bold text-indigo-700">
                    {initialsFromName(member.full_name)}
                  </div>
                </td>
                <td className="px-4 py-3 font-medium text-slate-900">{member.full_name}</td>
                <td className="px-4 py-3">{member.email}</td>
                <td className="px-4 py-3">
                  <span
                    className={`rounded-full px-2 py-1 text-xs font-semibold ${
                      member.status === "Online" ? "bg-emerald-100 text-emerald-700" : "bg-slate-100 text-slate-600"
                    }`}
                  >
                    {member.status}
                  </span>
                </td>
                <td className="px-4 py-3">
                  {permissions.can_manage ? (
                    <select
                      value={member.role}
                      onChange={(event) => handleRoleChange(member.id, event.target.value)}
                      className="rounded-md border border-slate-300 px-2 py-1 text-sm"
                    >
                      {ROLE_OPTIONS.map((roleOption) => (
                        <option value={roleOption} key={roleOption}>
                          {roleOption}
                        </option>
                      ))}
                    </select>
                  ) : (
                    <span className="capitalize">{member.role}</span>
                  )}
                </td>
                <td className="px-4 py-3">{new Date(member.joined_at).toLocaleDateString()}</td>
                <td className="px-4 py-3">
                  <div className="flex gap-2">
                    <button
                      type="button"
                      onClick={() => window.open(`/freelancer/profile/${member.user_id}`, "_blank")}
                      className="rounded-md border border-slate-300 px-2 py-1 text-xs hover:bg-slate-100"
                    >
                      View Profile
                    </button>
                    {permissions.can_manage && (
                      <button
                        type="button"
                        onClick={() => handleRemove(member.id)}
                        className="rounded-md border border-red-300 px-2 py-1 text-xs text-red-600 hover:bg-red-50"
                      >
                        Remove
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {pagination.totalPages > 1 && (
        <div className="mt-4 flex items-center justify-between">
          <p className="text-sm text-slate-500">Total members: {pagination.total}</p>
          <div className="flex gap-2">
            <button
              type="button"
              disabled={pagination.page <= 1}
              onClick={() => setPage((prev) => Math.max(prev - 1, 1))}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm disabled:opacity-50"
            >
              Prev
            </button>
            <span className="px-2 py-1 text-sm text-slate-600">
              {pagination.page} / {pagination.totalPages}
            </span>
            <button
              type="button"
              disabled={pagination.page >= pagination.totalPages}
              onClick={() => setPage((prev) => prev + 1)}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm disabled:opacity-50"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </section>
  );
};

export default TeamMembers;
